export async function getAccessCsrfToken(): Promise<string> {
  const token = readCookie('csrf_access_token')
  if (token) return token

  const snapshot = await getAuthCsrfSnapshot()
  if (snapshot.csrf_access_token) return snapshot.csrf_access_token
  throw sessionExpiredError()
}

async function getRefreshCsrfToken(): Promise<string> {
  const token = readCookie('csrf_refresh_token')
  if (token) return token

  const snapshot = await getAuthCsrfSnapshot()
  if (snapshot.csrf_refresh_token) return snapshot.csrf_refresh_token
  throw sessionExpiredError()
}

