  const accessible: Record<number, ImageBitmap[]> = { 1: [], 2: [], 3: [], 4: [] }

  for (const valley of [1, 2, 3, 4]) {
    const urls = definition.accessible[valley] ?? []
    accessible[valley] = await loadBitmapList(urls)
  }

  const blocked = await loadBitmapList(definition.blocked ?? [])
  const loadedCount =
    blocked.length + accessible[1].length + accessible[2].length + accessible[3].length + accessible[4].length

  if (loadedCount === 0) return null

  return {
    sourcePx: definition.sourcePx,
    accessible,
    blocked,
  }
}

export function closeTerrainTilesetBitmaps(tileset: TerrainTilesetBitmaps | null): void {
  if (!tileset) return
  closeBitmapList(tileset.blocked)
  closeBitmapList(tileset.accessible[1] ?? [])
  closeBitmapList(tileset.accessible[2] ?? [])
  closeBitmapList(tileset.accessible[3] ?? [])
  closeBitmapList(tileset.accessible[4] ?? [])
}

export function pickTerrainTilesetVariant(
  tileset: TerrainTilesetBitmaps | null,
  _x: number,
  _y: number,
  valley: number,
): ImageBitmap | null {
  if (!tileset) return null
  const variants = valley <= 0 ? tileset.blocked : (tileset.accessible[valley] ?? tileset.accessible[1] ?? [])
  if (!variants || variants.length === 0) return null
  return variants[0] ?? null
}
import { API_BASE_URL } from './apiBase'
import { fetchWithTimeout } from './http'

export type PublicUser = {
  _id: string
  username: string
  email: string
  google_email: string | null
  google_linked: boolean
  created_at: string
  updated_at: string
}

export type LoginRequest = {
  identifier: string
  password: string
}

export type RegisterRequest = {
  username: string
  email: string
  password: string
}

export type LoginResponse = {
  user: PublicUser
}

export type RegisterResponse = {
  message: string
  user: PublicUser
}

export type UserResponse = {
  user: PublicUser
}

export type GoogleLinkStartResponse = {
  url: string
}

type CsrfResponse = {
  csrf_token: string
}

export type AuthCsrfSnapshot = {
  csrf_access_token: string
  csrf_refresh_token: string
  anon_csrf: string
}

type ApiValidationError = {
  loc?: Array<string | number>
  msg?: string
}

type ApiErrorPayload = {
  detail?: string
  errors?: ApiValidationError[]
}

export class AuthApiError extends Error {
  status: number
  payload: ApiErrorPayload | null

  constructor(message: string, status: number, payload: ApiErrorPayload | null) {
    super(message)
    this.name = 'AuthApiError'
    this.status = status
    this.payload = payload
  }
}

function isLocalhost(hostname: string): boolean {
  return hostname === 'localhost' || hostname === '127.0.0.1' || hostname === '::1'
}

const AUTH_BASE_URL = `${API_BASE_URL}/api/v1/auth`
const AUTH_REQUEST_TIMEOUT_MS = 10000

function readCookie(name: string): string {
  const escaped = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
  const match = document.cookie.match(new RegExp(`(?:^|; )${escaped}=([^;]*)`))
  return match ? decodeURIComponent(match[1]) : ''
}

function assertSecureAuthTransport(): void {
  const apiUrl = new URL(API_BASE_URL, window.location.origin)
  const pageProtocol = window.location.protocol
  const apiProtocol = apiUrl.protocol
  const allowInsecure = import.meta.env.DEV && import.meta.env.VITE_ALLOW_INSECURE_AUTH === 'true'

  if (isLocalhost(apiUrl.hostname) || allowInsecure) return
  if (pageProtocol === 'https:' && apiProtocol === 'https:') return

  throw new AuthApiError(
    'Secure auth requires HTTPS for both frontend and backend. Set VITE_API_BASE_URL_DEV or VITE_API_BASE_URL_PROD to an https:// endpoint.',
    0,
    null,
  )
}

async function parseJsonSafe(response: Response): Promise<unknown> {
  try {
    return await response.json()
  } catch {
    return null
  }
}

function formatValidationErrors(errors: ApiValidationError[] | undefined): string[] {
  if (!errors || errors.length === 0) return []
  return errors.map((error) => {
    const path = Array.isArray(error.loc) ? error.loc.join('.') : 'field'
    const message = error.msg ?? 'Invalid value'
    return `${path}: ${message}`
  })
}

function extractErrorMessage(payload: ApiErrorPayload | null): string {
  if (payload?.detail) return payload.detail
  if (payload?.errors && payload.errors.length > 0) return 'Validation failed'
  return 'Request failed'
}

async function authRequest<T>(path: string, init: RequestInit): Promise<T> {
  assertSecureAuthTransport()
  const response = await fetchWithTimeout(
    `${AUTH_BASE_URL}${path}`,
    {
      ...init,
      credentials: 'include',
      headers: {
        'Content-Type': 'application/json',
        ...(init.headers ?? {}),
      },
    },
    AUTH_REQUEST_TIMEOUT_MS,
  )

  const payload = (await parseJsonSafe(response)) as ApiErrorPayload | T | null

  if (!response.ok) {
    const errorPayload = (payload as ApiErrorPayload) ?? null
    throw new AuthApiError(extractErrorMessage(errorPayload), response.status, errorPayload)
  }

  return payload as T
}

export async function getAnonCsrfToken(): Promise<string> {
  const data = await authRequest<CsrfResponse>('/csrf-token', { method: 'GET' })
  return data.csrf_token
}

export async function getAuthCsrfSnapshot(): Promise<AuthCsrfSnapshot> {
  const data = await authRequest<AuthCsrfSnapshot>('/csrf', { method: 'GET' })
  return {
    csrf_access_token: data.csrf_access_token ?? '',
    csrf_refresh_token: data.csrf_refresh_token ?? '',
    anon_csrf: data.anon_csrf ?? '',
  }
}

export async function login(payload: LoginRequest): Promise<LoginResponse> {
  const csrfToken = await getAnonCsrfToken()
  return authRequest<LoginResponse>('/login', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
    body: JSON.stringify(payload),
  })
}

export async function register(payload: RegisterRequest): Promise<RegisterResponse> {
  const csrfToken = await getAnonCsrfToken()
  return authRequest<RegisterResponse>('/register', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
    body: JSON.stringify(payload),
  })
}

export function beginGoogleSignIn(): void {
  assertSecureAuthTransport()
  window.location.assign(`${AUTH_BASE_URL}/google/login`)
}

function sessionExpiredError(): AuthApiError {
  return new AuthApiError('Your session has expired. Please sign in again.', 401, null)
}

export async function getAccessCsrfToken(): Promise<string> {
  const token = readCookie('csrf_access_token')
  if (token) return token

  const snapshot = await getAuthCsrfSnapshot()
  if (snapshot.csrf_access_token) return snapshot.csrf_access_token
  throw sessionExpiredError()
}

async function getRefreshCsrfToken(): Promise<string> {
  const token = readCookie('csrf_refresh_token')
  if (token) return token

  const snapshot = await getAuthCsrfSnapshot()
  if (snapshot.csrf_refresh_token) return snapshot.csrf_refresh_token
  throw sessionExpiredError()
}

async function refreshAccessToken(): Promise<void> {
  const refreshCsrfToken = await getRefreshCsrfToken()
  await authRequest<{ message: string }>('/refresh', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': refreshCsrfToken,
    },
  })
}

async function requestCurrentUserWithAccessCsrf(csrfToken: string): Promise<UserResponse> {
  return authRequest<UserResponse>('/me', {
    method: 'GET',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
  })
